import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { MapContainer, TileLayer, Marker, Popup } from 'react-leaflet';
import { Store, Plus } from 'lucide-react';
import ModalNuevaSucursal from './ModalNuevaSucursal'; // Importamos el nuevo componente

const Dashboard = () => {
  const navigate = useNavigate();
  const [showModal, setShowModal] = useState(false);
  const [locales, setLocales] = useState([
    { id: 1, nombre: "Sucursal Central", direccion: "San Miguel de Tucumán", coords: [-26.816, -65.230] }
  ]);

  const agregarSucursal = (datos) => {
    const nuevo = { id: Date.now(), ...datos };
    setLocales([...locales, nuevo]);
    setShowModal(false);
  };

  return (
    <div style={{ display: 'flex', height: 'calc(100vh - 75px)', background: '#f8fafc' }}>
      
      {/* SIDEBAR */}
      <div style={sidebarStyle}>
        <h2 style={{ marginBottom: '20px', display: 'flex', alignItems: 'center', gap: '10px' }}>
          <Store color="#e67e22" /> Mis Locales
        </h2>
        
        <div style={{ flex: 1, overflowY: 'auto' }}>
          {locales.map(local => (
            <div key={local.id} style={cardStyle}>
              <div style={{ flex: 1 }}>
                <strong style={{ display: 'block' }}>{local.nombre}</strong>
                <span style={{ fontSize: '0.8rem', color: '#64748b' }}>{local.direccion}</span>
              </div>
              <button onClick={() => navigate(`/ofertas/${local.id}`)} style={btnOfertaStyle}>
                Ofertas
              </button>
            </div>
          ))}
        </div>

        <button onClick={() => setShowModal(true)} style={btnNuevaSucursal}>
          <Plus size={20} /> Nueva Sucursal
        </button>
      </div>

      {/* MAPA */}
      <div style={{ flex: 1 }}>
        <MapContainer center={[-26.816, -65.230]} zoom={14} style={{ height: '100%', width: '100%' }}>
          <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
          {locales.map(local => (
            <Marker key={local.id} position={local.coords}>
              <Popup><strong>{local.nombre}</strong></Popup>
            </Marker>
          ))}
        </MapContainer>
      </div>

      {/* MODAL EXTERNO */}
      {showModal && (
        <ModalNuevaSucursal 
          onClose={() => setShowModal(false)} 
          onSave={agregarSucursal} 
        />
      )}
    </div>
  );
};

/* --- ESTILOS SIDEBAR --- */
const sidebarStyle = { width: '380px', padding: '25px', background: 'white', borderRight: '1px solid #e2e8f0', display: 'flex', flexDirection: 'column' };
const cardStyle = { padding: '15px', background: '#fff9f5', borderRadius: '12px', marginBottom: '12px', display: 'flex', alignItems: 'center', border: '1px solid #ffe8d6' };
const btnOfertaStyle = { background: '#e67e22', color: 'white', border: 'none', padding: '8px 12px', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' };
const btnNuevaSucursal = { background: '#1e293b', color: 'white', padding: '15px', borderRadius: '12px', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px', fontWeight: 'bold' };

export default Dashboard;
